public void testGenerateURLFragmentWithAmpersand() {
    StandardToolTipTagFragmentGenerator g
            = new StandardToolTipTagFragmentGenerator();
    assertEquals(" title=\"A &amp; B\" alt=\"\"",
            g.generateToolTipFragment("A & B"));
}

public void testGenerateURLFragmentWithLessThanGreaterThan() {
    StandardToolTipTagFragmentGenerator g
            = new StandardToolTipTagFragmentGenerator();
    assertEquals(" title=\"A &lt; B &gt; C\" alt=\"\"",
            g.generateToolTipFragment("A < B > C"));
}

public void testGenerateURLFragmentWithSingleQuote() {
    StandardToolTipTagFragmentGenerator g
            = new StandardToolTipTagFragmentGenerator();
    assertEquals(" title=\"It&#x27;s working\" alt=\"\"",
            g.generateToolTipFragment("It's working"));
}

public void testGenerateURLFragmentWithMixedSpecialChars() {
    StandardToolTipTagFragmentGenerator g
            = new StandardToolTipTagFragmentGenerator();
    assertEquals(" title=\"&lt;&quot;A&amp;B&quot;&gt;\" alt=\"\"",
            g.generateToolTipFragment("<\"A&B\">"));
}
